    faq: t([{ q: 'Will I look "pulled"?', a: 'No, because we move the muscle, the skin sits naturally without tension.' }], [{ q: 'Voi arăta "trasă"?', a: 'Nu, deoarece mutăm mușchiul, pielea se așază natural.' }], [{ q: "¿Pareceré \"tirado\"?", a: "No, debido a que movemos el músculo, la piel se asienta naturalmente sin tensión." }], [{ q: "Sembrerò \"tirato\"?", a: "No, poiché muoviamo i muscoli, la pelle si adatta naturalmente senza tensioni." }], [{ q: "Буду ли я выглядеть «вытянутым»?", a: "Нет, поскольку мы двигаем мышцами, кожа сидит естественно, без напряжения." }], [{ q: "Est-ce que j'aurai l'air « tiré » ?", a: "Non, parce que nous bougeons le muscle, la peau repose naturellement sans tension." }], [{ q: "Werde ich „angezogen“ aussehen?", a: "Nein, da wir den Muskel bewegen, sitzt die Haut natürlich und spannungsfrei." }])
